retornaAutorizacao.Call('WWTABELAPRECO', Status_SimNao.Sim, 2, &AutNiv) tb2.Visible = 1 tb1.Visible = 0 informativo.ForeColor = RGB(20,120,75) LoadWWPContext.Call(&Context) &FilCod = &Context.FilCod &IsGrid2 = false &IsGrid3 = false &IsGrid1 = false &PrimeiraLinha = 1 &ColunaProduto = 1 &Colunavlr = 2 TextBlockTitle.Caption = 'Importar Produtos da Tabela: ' + trim(&TabCod)
