/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'AttributesSecurityCode' Grid.Rows = 2000 &GridCurrentPage = 1 &GridCurrentPage.Visible = False &GridPageCount = -1 Grid2.Rows = 2000 &Grid2CurrentPage = 1 &Grid2CurrentPage.Visible = False &Grid2PageCount = -1 GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows Grid2PaginationBar.RowsPerPageSelectedValue = Grid2.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&Grid1TabPrc1.Visible = iif(&Tem1= 1,1,0) &Grid1TabPrc2.Visible = iif(&Tem2= 1,1,0) &Grid1TabPrc3.Visible = iif(&Tem3= 1,1,0) &Grid1TabPrc4.Visible = iif(&Tem4= 1,1,0) &Grid1TabPrc5.Visible = iif(&Tem5= 1,1,0) &Grid1TabPrc6.Visible = iif(&Tem6= 1,1,0) &Grid1TabPrc7.Visible = iif(&Tem7= 1,1,0) &Grid1TabPrc8.Visible = iif(&Tem8= 1,1,0) &Grid1TabPrc9.Visible = iif(&Tem9= 1,1,0)
