Event Grid.Load
&Grid1TabPrc1.Visible = iif(&Tem1= 1,1,0) &Grid1TabPrc2.Visible = iif(&Tem2= 1,1,0) &Grid1TabPrc3.Visible = iif(&Tem3= 1,1,0) &Grid1TabPrc4.Visible = iif(&Tem4= 1,1,0) &Grid1TabPrc5.Visible = iif(&Tem5= 1,1,0) &Grid1TabPrc6.Visible = iif(&Tem6= 1,1,0) &Grid1TabPrc7.Visible = iif(&Tem7= 1,1,0) &Grid1TabPrc8.Visible = iif(&Tem8= 1,1,0) &Grid1TabPrc9.Visible = iif(&Tem9= 1,1,0)
&count = 0 &IsGrid1 = false for &SdtTabelaPrecoItem in &SdtTabelaPreco If &SdtTabelaPrecoItem.Erro = 'N' &IsGrid1 = true &grid1ProCod = &SdtTabelaPrecoItem.ProCod &grid1ProRef = &SdtTabelaPrecoItem.PrograRef &grid1ProNom = &SdtTabelaPrecoItem.ProNom &Grid1TabPrc1 = &SdtTabelaPrecoItem.TabPrc1 &Grid1TabPrc2 = &SdtTabelaPrecoItem.TabPrc2 &Grid1TabPrc3 = &SdtTabelaPrecoItem.TabPrc3 &Grid1TabPrc4 = &SdtTabelaPrecoItem.TabPrc4 &Grid1TabPrc5 = &SdtTabelaPrecoItem.TabPrc5 &Grid1TabPrc6 = &SdtTabelaPrecoItem.TabPrc6 &Grid1TabPrc7 = &SdtTabelaPrecoItem.TabPrc7 &Grid1TabPrc8 = &SdtTabelaPrecoItem.TabPrc8 &Grid1TabPrc9 = &SdtTabelaPrecoItem.TabPrc9 &count +=1
