&grid2ProCod = &SdtTabelaPrecoItem.ProCod &grid2ProRef = &SdtTabelaPrecoItem.PrograRef &grid2ProNom = &SdtTabelaPrecoItem.ProNom &Grid2Mensagem = &SdtTabelaPrecoItem.Mensagem
