Event scaProgressBar1.OnComplete
WWTabelaPreco.Link()
EndEvent
Event Enter
If &SdtTabelaPreco.Count > 0 &IsPossui = False For &SdtTabelaPrecoItem in &SdtTabelaPreco If &SdtTabelaPrecoItem.Erro = 'N' &IsPossui = true EndIF EndFor
If &IsPossui = true &padObs = PadL(str(&PrimeiraLinha), 3, ' ') + PadL(str(&ColunaProduto), 3, ' ') + PadL(str(&Colunavlr), 3, ' ') padraoUsuario.Call('G', &Pgmname, &Context.PesCod, &Context.EmpCod, &padObs, &PadDtaMod)
tb2.Visible = 0 tb1.Visible = 1 &ProgressId = 'ImportaTabelaPreco' + trim(Str(&Context.EmpCod)) + trim(Str(&Context.FilCod)) + trim(Str(&Context.PesCod)) &ProgressId = &ProgressId.trim() scaProgressBar1.ProcessId = &ProgressId scaProgressBar1.UpdateProgressURL = retornaProgresso.Link(&ProgressId) scaProgressBar1.Start()
GravaProdutosImportados.Submit('GravaProdutosImportados', &ProgressId, &EmpCod, &TabCod, &SdtTabelaPreco, &Context.UserName) Else msg('Nenhum produto sem erro a ser gravado ao Pedido.') EndIF Else msg('Nenhum produto a ser gravado.') EndIf
EndEvent
Event FileUpload1.UploadComplete
&SdtTabelaPreco.Clear()
For &FileUploadData in &FileUploadDataColl If not &FileUploadData.File.IsEmpty() &File.Source=&FileUploadData.File &selectedURL = &File.GetAbsoluteName() /// Pega o local temporario &File.Close()
ImportaTabelaPreco.Call(&EmpCod, &FilCod, &TabCod, &selectedURL, &PrimeiraLinha, &ColunaProduto, &Colunavlr, &SdtTabelaPreco)
grid2.Refresh() grid.Refresh() Endif endfor
&FileUploadDataColl.clear() FileUpload1.Clear()
EndEvent
